/**
 * Fix `.d.ts` import paths generated by tsc + verbatimModuleSyntax.
 *
 * TypeScript 5.0+ with `rewriteRelativeImportExtensions` should handle this,
 * but as of TS 6.0 the emitted declaration files still carry `.ts` extensions
 * in relative import paths. This script rewrites the `.ts` extension to `.js`
 * so the declarations resolve under every consumer moduleResolution mode —
 * including `node16` / `nodenext`, which reject extensionless relative imports
 * (TS2834) and require the runtime `.js` extension.
 */

import { readdirSync, readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { fileURLToPath } from 'node:url';

const dist = join(fileURLToPath(import.meta.url), '..', '..', 'dist');
const files = readdirSync(dist, { recursive: true })
  .filter((f) => typeof f === 'string' && f.endsWith('.d.ts'));

for (const f of files) {
  const p = join(dist, f);
  const src = readFileSync(p, 'utf8');
  const updated = src.replace(/(from\s+'[^']+)\.ts'/g, "$1.js'");
  if (src !== updated) writeFileSync(p, updated);
}
